package agent

import (
	"encoding/json"
	"fmt"
	"strconv"
	"strings"
	"time"
)

// Session log JSONL schema reference.
//
// The agent harness writes one event per line to .ddx/agent-logs/agent-*.jsonl
// (or to the per-run SessionLogDir override). Every line has the envelope:
//
//	{"session_id": string, "seq": int, "type": string, "ts": RFC3339Nano, "data": {...}}
//
// The standard schema is always emitted and is what existing tooling consumes.
// Diagnostic logging is opt-in via DDX_LOG_VERBOSE=1; when set, the writer adds
// raw body fields so a session can be replayed and root-caused without loss of
// inputs and outputs. Diagnostic fields are strictly additive: event ordering
// and event types stay the same across harnesses.
//
// Per-event-type fields:
//
//	session.start:
//	  data.model       string  — model id reported by the harness
//	  data.session_id  string  — session id from the harness CLI
//	  data.bead_id     string  — bead under which the session ran (may be "")
//	  data.elapsed_ms  int     — ms since session start (always 0 here)
//	  data.harness     string  — "claude" | "fiz" | etc.
//
//	llm.request:
//	  data.attempt_index int        — request attempt counter (0-based)
//	  data.messages      []object   — conversation messages (last user message hint used by the renderer)
//
//	llm.response:
//	  data.model         string  — resolved model id
//	  data.latency_ms    int     — per-call wall time (request → response)
//	  data.tool_calls    []{name} — tool_use names emitted in this turn
//	  data.turn          int     — 1-based assistant turn count
//	  data.bead_id       string
//	  data.elapsed_ms    int     — ms since session start
//	  data.input_tokens  int     — running input tokens (latest seen)
//	  data.output_tokens int     — running output tokens (latest seen)
//	  data.attempt.cost.raw.total_tokens int — running total
//
//	llm.response (diagnostic adds):
//	  data.content       string  — concatenated assistant text blocks for this turn
//	  data.finish_reason string  — claude stop_reason ("end_turn", "tool_use", "max_tokens", ...)
//	  data.usage object:
//	    input_tokens                int
//	    output_tokens               int
//	    cache_creation_input_tokens int
//	    cache_read_input_tokens     int
//	    total_tokens                int
//
//	tool.call:
//	  data.tool       string         — tool name
//	  data.input      object         — tool arguments as decoded JSON
//	  data.bead_id    string
//	  data.elapsed_ms int            — ms since session start
//	  data.turn       int            — assistant turn that issued the call
//
//
//	tool.result:
//	  data.tool         string
//	  data.output_bytes int
//	  data.duration_ms  int     — wall time from tool_use → tool_result
//	  data.error        string  — non-empty when tool_result is_error=true; empty otherwise
//	  data.bead_id      string
//	  data.elapsed_ms   int
//	  data.turn         int
//
//	tool.result (diagnostic adds):
//	  data.output string — tool_result content (joined if structured)
//
// Diagnostic logging is off by default; existing consumers of the standard
// schema (TailSessionLogs, FormatSessionLogLines, the server worker log
// endpoint) keep working unchanged because they tolerate extra fields.

// FormatSessionLogLines formats Fizeau-style JSONL log entries into readable progress.
// It is used by both the CLI (local execute-loop) and the server worker log endpoint.
func FormatSessionLogLines(lines []string) string {
	var sb strings.Builder
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry map[string]any
		if err := json.Unmarshal([]byte(line), &entry); err != nil {
			continue
		}
		entryType, _ := entry["type"].(string)
		switch entryType {
		case "session.start":
			model, _ := entry["data"].(map[string]any)["model"].(string)
			fmt.Fprintf(&sb, "▶ session started (model: %s)\n", model)
		case "llm.request":
			data, _ := entry["data"].(map[string]any)
			attemptIdx, _ := data["attempt_index"].(float64)
			requestBytes := encodedPayloadSize(data["messages"])
			// Extract a hint from the last user message in the conversation.
			promptHint := ""
			if msgs, ok := data["messages"].([]any); ok {
				for i := len(msgs) - 1; i >= 0; i-- {
					if msg, ok := msgs[i].(map[string]any); ok {
						if role, _ := msg["role"].(string); role == "user" {
							if content, _ := msg["content"].(string); content != "" {
								promptHint = " [" + truncateStr(strings.TrimSpace(content), 60) + "]"
							}
							break
						}
					}
				}
			}
			sizeHint := formatSizeSuffix("req", requestBytes)
			fmt.Fprintf(&sb, "  → llm request (attempt %.0f%s)%s\n", attemptIdx, sizeHint, promptHint)
		case "llm.response":
			data, _ := entry["data"].(map[string]any)
			model, _ := data["model"].(string)
			latency, _ := data["latency_ms"].(float64)
			responseBytes := progressInt(data, "response_bytes")
			if responseBytes <= 0 {
				responseBytes = encodedPayloadSize(data["content"])
			}
			thinkingBytes := progressInt(data, "thinking_bytes")
			toolInputBytes := progressInt(data, "tool_input_bytes")
			// Tokens: data.attempt.cost.raw.total_tokens
			var tokens float64
			if attempt, ok := data["attempt"].(map[string]any); ok {
				if cost, ok := attempt["cost"].(map[string]any); ok {
					if raw, ok := cost["raw"].(map[string]any); ok {
						tokens, _ = raw["total_tokens"].(float64)
					}
				}
			}
			// Tool calls from response
			toolCalls, _ := data["tool_calls"].([]any)
			finishReason, _ := data["finish_reason"].(string)
			suffix := ""
			if len(toolCalls) > 0 {
				var names []string
				for _, tc := range toolCalls {
					if tcm, ok := tc.(map[string]any); ok {
						n, _ := tcm["name"].(string)
						if n != "" {
							names = append(names, n)
						}
					}
				}
				suffix = fmt.Sprintf(" → %s", strings.Join(names, ", "))
			} else if finishReason != "" {
				suffix = fmt.Sprintf(" (%s)", finishReason)
			}
			byteHints := formatPayloadHints([]payloadHint{
				{label: "text", bytes: responseBytes},
				{label: "think", bytes: thinkingBytes},
				{label: "tool_in", bytes: toolInputBytes},
			})
			if byteHints != "" {
				byteHints = ", " + byteHints
			}
			fmt.Fprintf(&sb, "  ← llm response (%.0f tokens, %.1fs%s) %s%s\n", tokens, latency/1000, byteHints, model, suffix)
		case "llm.delta":
			// Skip deltas — too verbose for summary
		case "progress":
			if line := formatProgressLogEntry(entry); line != "" {
				fmt.Fprint(&sb, line)
			}
		case "tool.call":
			data, _ := entry["data"].(map[string]any)
			name, _ := data["tool"].(string)
			inp, _ := data["input"].(map[string]any)
			dur, _ := data["duration_ms"].(float64)
			inputBytes := progressInt(data, "input_bytes")
			if inputBytes <= 0 {
				inputBytes = encodedPayloadSize(inp)
			}
			output, _ := data["output"].(string)
			outputBytes := progressInt(data, "output_bytes")
			if outputBytes <= 0 {
				outputBytes = len([]byte(output))
			}
			argHint := ""
			if len(inp) > 0 {
				// Prefer path/command/query keys for display
				for _, key := range []string{"path", "command", "query", "file"} {
					if v, ok := inp[key]; ok {
						argHint = truncateStr(fmt.Sprintf("%v", v), 60)
						break
					}
				}
				if argHint == "" {
					for _, v := range inp {
						argHint = truncateStr(fmt.Sprintf("%v", v), 60)
						break
					}
				}
				argHint = compactToolDisplay("", argHint)
			}
			errMsg, _ := data["error"].(string)
			errSuffix := ""
			if errMsg != "" {
				errSuffix = fmt.Sprintf(" ❌ %s", truncateStr(errMsg, 40))
			}
			durSuffix := ""
			if dur > 0 {
				durSuffix = fmt.Sprintf(" (%.1fs)", dur/1000)
			}
			sizeSuffix := formatPayloadHints([]payloadHint{
				{label: "in", bytes: inputBytes},
				{label: "out", bytes: outputBytes},
			})
			if sizeSuffix != "" {
				sizeSuffix = " " + sizeSuffix
			}
			fmt.Fprintf(&sb, "  🔧 %s %s%s%s%s\n", name, argHint, sizeSuffix, durSuffix, errSuffix)
		case "tool.result", "tool_result":
			data, _ := entry["data"].(map[string]any)
			name, _ := data["tool"].(string)
			if name == "" {
				name, _ = data["name"].(string)
			}
			output, _ := data["output"].(string)
			outputBytes := progressInt(data, "output_bytes")
			if outputBytes <= 0 {
				outputBytes = len([]byte(output))
			}
			dur, _ := data["duration_ms"].(float64)
			errMsg, _ := data["error"].(string)
			durSuffix := ""
			if dur > 0 {
				durSuffix = " " + (time.Duration(int64(dur)) * time.Millisecond).String()
			}
			errSuffix := ""
			if errMsg != "" {
				errSuffix = " failed"
			}
			name = compactToolDisplay(name, "")
			fmt.Fprintf(&sb, "  < %s out=%s%s%s\n",
				name, formatByteSize(outputBytes), durSuffix, errSuffix)
		case "bead.claimed":
			data, _ := entry["data"].(map[string]any)
			beadID, _ := data["bead_id"].(string)
			title, _ := data["title"].(string)
			if title != "" {
				fmt.Fprintf(&sb, "\n▶ %s: %s\n", beadID, title)
			} else {
				fmt.Fprintf(&sb, "\n▶ %s\n", beadID)
			}
		case "bead.result":
			data, _ := entry["data"].(map[string]any)
			beadID, _ := data["bead_id"].(string)
			status, _ := data["status"].(string)
			detail, _ := data["detail"].(string)
			resultRev, _ := data["result_rev"].(string)
			preserveRef, _ := data["preserve_ref"].(string)
			rationale, _ := data["no_changes_rationale"].(string)

package agent

import (
	"bufio"
	"context"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"
)

type fileTrackState struct {
	offset int64
}

type sessionLogFile struct {
	path string
}

// TailSessionLogs watches the agent log directory for new/modified session log
// files and writes formatted progress to dst. It stops when ctx is cancelled.
// Callers should run this in a goroutine while ExecuteBead runs synchronously.
func TailSessionLogs(ctx context.Context, projectRoot string, dst io.Writer) {
	logDir := filepath.Join(projectRoot, DefaultLogDir)
	states := make(map[string]*fileTrackState)

	// Record existing files so we don't replay old logs
	for _, file := range listSessionLogFiles(projectRoot, logDir) {
		if info, err := os.Stat(file.path); err == nil {
			states[file.path] = &fileTrackState{offset: info.Size()}
		}
	}

	ticker := time.NewTicker(500 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			readNewLogLines(projectRoot, logDir, states, dst)
			return
		case <-ticker.C:
			readNewLogLines(projectRoot, logDir, states, dst)
		}
	}
}

// readNewLogLines reads any new lines from agent session logs and formats them.
func readNewLogLines(projectRoot, logDir string, states map[string]*fileTrackState, dst io.Writer) {
	for _, file := range listSessionLogFiles(projectRoot, logDir) {
		path := file.path
		st, err := os.Stat(path)
		if err != nil {
			continue
		}

		fs, ok := states[path]
		if !ok {
			fs = &fileTrackState{}
			states[path] = fs
		}

		if st.Size() <= fs.offset {
			continue
		}

		f, err := os.Open(path)
		if err != nil {
			continue
		}

		_, _ = f.Seek(fs.offset, io.SeekStart)
		scanner := bufio.NewScanner(f)
		// 16MB max line. Session-log `response` fields observed up to ~7MB in
		// real incidents (2026-04-20 reviewer-malfunction report). Matches bead
		// store and claude stream for consistency.
		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
		var newLines []string
		for scanner.Scan() {
			line := scanner.Text()
			if strings.TrimSpace(line) != "" {
				newLines = append(newLines, line)
			}
		}
		fs.offset, _ = f.Seek(0, io.SeekCurrent)
		f.Close()

		if len(newLines) > 0 {
			formatted := FormatSessionLogLines(newLines)
			if formatted != "" {
				fmt.Fprint(dst, formatted)
			}
		}
	}
}

func listSessionLogFiles(projectRoot, logDir string) []sessionLogFile {
	var files []sessionLogFile
	appendDirLogs := func(dir string) {
		entries, err := os.ReadDir(dir)
		if err != nil {
			return
		}
		for _, entry := range entries {
			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".jsonl") {
				continue
			}
			name := entry.Name()
			if strings.HasPrefix(name, "agent-loop-") {
				continue
			}
			if strings.HasPrefix(name, "agent-") || strings.HasPrefix(name, "svc-") {
				files = append(files, sessionLogFile{path: filepath.Join(dir, name)})
			}
		}
	}

	appendDirLogs(logDir)
	embeddedDirs, _ := filepath.Glob(filepath.Join(projectRoot, ".ddx", "executions", "*", "embedded"))
	for _, dir := range embeddedDirs {
		appendDirLogs(dir)
	}
	return files
}

package agent

import (
	"encoding/json"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestFormatSessionLogLines_ProgressThinking(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":   "thinking",
			"state":   "start",
			"message": "ddx-99419bc1 #1 thinking ...",
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":           "thinking",
			"state":           "update",
			"message":         "ddx-99419bc1 #1 thinking update: reviewing files",
			"session_summary": "reviewing files",
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":         "thinking",
			"state":         "complete",
			"message":       "ddx-99419bc1 #1 thought 5.0s",
			"output_tokens": 8,
			"duration_ms":   5000,
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  thinking ...\n")
	assert.Contains(t, got, "  thinking update: reviewing files\n")
	assert.Contains(t, got, "  thinking complete 8 tok in 5s\n")
}

func TestFormatSessionLogLines_LLMPayloadSizes(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "llm.request", map[string]any{
			"attempt_index": 0,
			"messages": []map[string]any{
				{"role": "user", "content": "inspect routing logs"},
			},
		}),
		mustSessionLogLine(t, "llm.response", map[string]any{
			"model":            "claude-sonnet-4-6",
			"latency_ms":       2500,
			"response_bytes":   17,
			"thinking_bytes":   2048,
			"tool_input_bytes": 32,
			"attempt": map[string]any{
				"cost": map[string]any{
					"raw": map[string]any{"total_tokens": 42},
				},
			},
			"tool_calls": []map[string]any{{"name": "Bash"}},
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  → llm request (attempt 0, req=")
	assert.Contains(t, got, "[inspect routing logs]\n")
	assert.Contains(t, got, "  ← llm response (42 tokens, 2.5s, text=17B think=2.0KB tool_in=32B) claude-sonnet-4-6 → Bash\n")
}

func TestFormatSessionLogLines_ProgressTool(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":     "tool",
			"state":     "start",
			"tool_name": "shell",
			"command":   "ls -al",
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":        "tool",
			"state":        "complete",
			"tool_name":    "shell",
			"command":      "ls -al /tmp/project/with/a/very/long/path/that/should/be/truncated/because/operators/do/not/need/full/output",
			"duration_ms":  3000,
			"total_tokens": 100,
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  > ls -al\n")
	assert.Contains(t, got, "  ok ls -al /tmp/project/with/a/very/long/path/that/should/be/truncated/")
	assert.Contains(t, got, " 3s 100tok\n")
	assert.NotContains(t, got, "operators/do/not/need/full/output")
}

func TestFormatSessionLogLines_ProgressToolStripsShellWrapper(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":       "tool",
			"state":       "complete",
			"tool_name":   "bash",
			"command":     `/bin/zsh -lc "go test ./cmd -run TestAgentRouteStatus -count=1"`,
			"duration_ms": 3200,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":       "tool",
			"state":       "complete",
			"tool_name":   "bash",
			"command":     `{command="/bin/bash -lc \"rg -n \\\"pre-execute\\\" .\""}`,
			"duration_ms": 40,
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  ok go test ./cmd -run TestAgentRouteStatus -count=1 3.2s\n")
	assert.Contains(t, got, "  ok rg -n \"pre-execute\" . 40ms\n")
	assert.NotContains(t, got, "/bin/zsh -lc")
	assert.NotContains(t, got, "/bin/bash -lc")
	assert.NotContains(t, got, "{command=")
}

func TestFormatSessionLogLines_ToolPayloadSizes(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "tool.call", map[string]any{
			"tool":        "Bash",
			"input":       map[string]any{"command": `/bin/zsh -lc "go test ./..."`},
			"input_bytes": 128,
		}),
		mustSessionLogLine(t, "tool.result", map[string]any{
			"tool":         "Bash",
			"output_bytes": 4096,
			"duration_ms":  1200,
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  🔧 Bash go test ./... in=128B\n")
	assert.NotContains(t, got, "/bin/zsh -lc")
	assert.Contains(t, got, "  < Bash out=4.0KB 1.2s\n")
}

func TestFormatSessionLogLines_ProgressResponseAndContext(t *testing.T) {
	lines := []string{
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":        "response",
			"state":        "complete",
			"message":      "ddx-99419bc1 #1 done 100tok",
			"total_tokens": 100,
			"duration_ms":  4200,
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":           "context",
			"state":           "update",
			"message":         "ddx-99419bc1 #1 context edited routing output and verified tests",
			"session_summary": "edited routing output and verified tests",
		}),
		mustSessionLogLine(t, "progress", map[string]any{
			"phase":           "compaction",
			"state":           "complete",
			"tokens_before":   4800,
			"tokens_after":    1200,
			"session_summary": "trimmed prompt history and preserved tool outputs",
		}),
	}

	got := FormatSessionLogLines(lines)
	assert.Contains(t, got, "  response complete 100 tok in 4.2s\n")
	assert.Contains(t, got, "  context summary: edited routing output and verified tests\n")
	assert.Contains(t, got, "  compaction complete 4800 -> 1200 tokens: trimmed prompt history and preserved tool outputs\n")
}

func mustSessionLogLine(t *testing.T, typ string, data map[string]any) string {
	t.Helper()
	body, err := json.Marshal(map[string]any{
		"type": typ,
		"data": data,
	})
	require.NoError(t, err)
	return string(body)
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	agenttry "github.com/DocumentDrivenDX/ddx/internal/agent/try"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, tier bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log                   io.Writer
	EventSink             io.Writer
	ProgressCh            chan<- ProgressEvent
	PreClaimHook          func(ctx context.Context) error
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, is invoked between nextCandidate and
	// Claim. It is expected to call upstream ResolveRoute against the
	// loop's resolved (harness, model) and return whatever typed routing
	// error the upstream surfaced — notably agent.ErrHarnessModelIncompatible
	// when the harness allow-list rejects the model. Any non-nil error
	// causes the loop to exit immediately without claiming the bead, with
	// a worker-level execution_failed record naming the rejected pair.
	// DDx does NOT duplicate the upstream allow-list; this gate only
	// consumes the typed-incompatibility surface.
	RoutePreflight func(ctx context.Context, harness, model string) error
	Once           bool
	PollInterval   time.Duration
	NoReview       bool
	LabelFilter    string
	SessionID      string
	WorkerID       string
	ProjectRoot    string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid a poll-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// MaxLoopCooldown is the absolute upper bound the execute-loop will set for
// any execute-loop-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set execute-loop-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// LandConflictCooldown is the short cooldown applied when all conflict-recovery
// paths fail (3-way ort auto-merge + optional focused-resolve agent) and the
// bead is parked as land_conflict_unresolvable. Much shorter than
// MaxLoopCooldown because land conflicts often resolve quickly as sibling beads
// advance the base branch.
const LandConflictCooldown = 15 * time.Minute

// StoreErrorCooldown is the short cooldown applied when a Store.* operation in
// the outcome-handling block returns a transient error. It prevents an
// immediate re-queue of the affected bead while allowing the loop to continue
// to the next candidate. Store errors during outcome handling are non-fatal:
// they are logged and emitted as loop-error events but do not terminate the
// worker.
const StoreErrorCooldown = 5 * time.Minute

// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
// the worker's result under refs/ddx/iterations/, records checks-blocked
// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
// without ever calling submit. On pass, honoured checks-bypass annotations are
// recorded as checks-bypass events and submit runs normally.
//
// submit is the project's land coordinator entry point (typically
// LocalLandCoordinator.Submit or the server-side coordinator submit).
//
// The implementation lives in checks_premerge.go alongside its supporting
// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
// loop's land-back call site is one obvious helper rather than three nested
// ones, and so callers wiring the gate do not need to import the helper layer
// directly.
func SubmitWithPreMergeChecks(
	ctx context.Context,
	projectRoot string,
	b *bead.Bead,
	res *ExecuteBeadResult,
	submit func(LandRequest) (*LandResult, error),
	eventStore BeadEventAppender,
	actor, source string,
	now func() time.Time,
) (*LandResult, *PreMergeChecksOutcome, error) {
	if now == nil {
		now = time.Now
	}
	if submit == nil {
		return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
	}
	evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
	outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
	if err != nil {
		// Treat checks_bypass / loader errors as a hard preserve: the worker
		// did its job; the operator misconfigured the gate. Better to park
		// the result under an iteration ref than to silently land it.
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
			return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
		}
		return &LandResult{
			Status:      "preserved",
			PreserveRef: ref,
			Reason:      "pre-merge checks setup error: " + err.Error(),
		}, nil, nil
	}
	if outcome.Blocked {
		land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
		if perr != nil {
			return nil, outcome, perr
		}
		if eventStore != nil {
			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
		}
		return land, outcome, nil
	}
	if eventStore != nil && len(outcome.Bypassed) > 0 {
		_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
	}
	land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
	return land, outcome, sErr
}

// handleOutcomeStoreError is called when a Store.* operation in the
// post-Execute outcome block returns a non-nil error. It logs the error,
// appends a kind:loop-error event to the bead (best-effort), sets a short
// cooldown so the bead is not immediately re-queued, increments
// result.Failures, and returns true — signalling the caller to continue to
// the next loop iteration rather than returning.
//
// If ctx is already cancelled, it returns false so the caller can propagate
// the cancellation immediately.
func (w *ExecuteBeadWorker) handleOutcomeStoreError(ctx context.Context, beadID, operation string, storeErr error, assignee string, result *ExecuteBeadLoopResult, runtime ExecuteBeadLoopRuntime, now func() time.Time) bool {
	if ctx.Err() != nil {
		return false
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "outcome store error (%s %s): %v (continuing)\n", operation, beadID, storeErr)
	}
	_ = w.Store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "loop-error",
		Summary:   operation + " failed",
		Body:      storeErr.Error(),
		Actor:     assignee,
		Source:    "ddx agent execute-loop",
		CreatedAt: now().UTC(),
	})
	cooldownUntil := now().UTC().Add(StoreErrorCooldown)
	_ = w.Store.SetExecutionCooldown(beadID, cooldownUntil, "loop-error", operation+": "+storeErr.Error())
	result.Failures++
	result.LastFailureStatus = "loop-error"
	return true
}

// runPostAttemptTriage invokes the optional post-attempt triage hook after
// the attempt outcome has been finalized but before any cooldown decision is
// applied. Hook failures are fail-open: the report is returned unchanged and
// legacy cooldown behavior remains in force.
func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
	hook := runtime.PostAttemptTriageHook
	if hook == nil {
		return report
	}
	triage, err := hook(ctx, candidate.ID, report)
	if err != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
		}
		return report
	}
	if strings.TrimSpace(triage.Classification) == "" {
		return report
	}
	report.OutcomeReason = triage.Classification
	recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
	return report
}

// CapLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
// The loop uses this for every SetExecutionCooldown call so no automatic
// path can silently park a bead for a year.
func CapLoopCooldown(d time.Duration) time.Duration {
	if d <= 0 {
		return 0
	}
	if d > MaxLoopCooldown {
		return MaxLoopCooldown
	}
	return d
}

