// option), the caller falls back to the non-streaming path via
// runClaudeWithFallbackFn.
func runClaudeStreamingFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
	args := BuildArgs(harness, buildArgsInputFromRunArgs(resolvedOpts), model)

	start := time.Now()
	runCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	cmd := osexec.CommandContext(runCtx, harness.Binary, args...)
	if execDir != "" {
		cmd.Dir = execDir
	}
	if harness.PromptMode == "stdin" {
		cmd.Stdin = strings.NewReader(prompt)
	}

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return nil, err
	}
	stderrPipe, err := cmd.StderrPipe()
	if err != nil {
		return nil, err
	}

	if err := cmd.Start(); err != nil {
		return nil, err
	}

	// Open the progress log file. Using agent-<sessionID>.jsonl so
	// TailSessionLogs (which only reads files matching "agent-*.jsonl")
	// picks the stream up automatically.
	sessionID := fmt.Sprintf("claude-%d", time.Now().UnixNano())
	beadID := ""
	if resolvedOpts.Correlation != nil {
		beadID = resolvedOpts.Correlation["bead_id"]
	}
	var progressLog *os.File
	progressLogDir := resolveClaudeProgressLogDir(resolvedOpts, r.Config)
	if progressLogDir != "" {
		if err := os.MkdirAll(progressLogDir, 0o755); err == nil {
			logPath := filepath.Join(progressLogDir, "agent-"+sessionID+".jsonl")
			if f, err := os.OpenFile(logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644); err == nil {
				progressLog = f
				defer progressLog.Close()
			}
		}
	}

	// Stream stdout: parse events as they arrive and mirror raw bytes into
	// a buffer so we can return the full output for session logging.
	var rawOut strings.Builder
	stdoutReader, stdoutWriter := io.Pipe()
	var parseResult *claudeStreamResult
	var parseErr error
	var parseWG sync.WaitGroup
	parseWG.Add(1)
	go func() {
		defer parseWG.Done()
		parseResult, parseErr = parseClaudeStream(stdoutReader, progressLog, sessionID, beadID, start)
	}()

	// Tee stdout into rawOut (for the final Result.Output) and the parser.
	stdoutDone := make(chan struct{})
	go func() {
		defer close(stdoutDone)
		// Pipe bytes through a tee so both the raw buffer and the parser see them.
		tee := io.TeeReader(stdoutPipe, &stringWriter{&rawOut})
		_, _ = io.Copy(stdoutWriter, tee)
		_ = stdoutWriter.Close()
	}()

	var stderrBuf strings.Builder
	stderrDone := make(chan struct{})
	go func() {
		defer close(stderrDone)
		_, _ = io.Copy(&stringWriter{&stderrBuf}, stderrPipe)
	}()

	// Idle-timeout watchdog: if no stdout progress for `timeout` duration,
	// cancel the context. The tee+parse goroutines handle activity naturally
	// via the pipe; for simplicity we use an overall deadline here. The
	// existing stream-json output is frequent enough that a long per-bead
	// deadline is the right behavior for operators.
	var timedOut bool
	if timeout > 0 {
		stop := make(chan struct{})
		go func() {
			select {
			case <-stop:
			case <-time.After(timeout):
				timedOut = true
				cancel()
			}
		}()
		defer close(stop)
	}

	<-stdoutDone
	<-stderrDone
	parseWG.Wait()
	runErr := cmd.Wait()
	elapsed := time.Since(start)

	exitCode := 0
	if runErr != nil {
		if exitErr, ok := runErr.(*osexec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else if errors.Is(runCtx.Err(), context.DeadlineExceeded) || timedOut {
			exitCode = -1
		} else {
			exitCode = -1
		}
	}

	execResult := &ExecResult{
		Stdout:   rawOut.String(),
		Stderr:   stderrBuf.String(),
		ExitCode: exitCode,
	}

	var execErr error
	if timedOut {
		execErr = context.DeadlineExceeded
	} else if runErr != nil && exitCode == 0 {
		execErr = runErr
	}

	result := r.processResult(harnessName, model, harness, execResult, execErr, elapsed, runCtx)

	// If the parser succeeded, prefer its aggregated values — they come from
	// the authoritative "result" event and may be more accurate than the
	// legacy extractor path.
	if parseErr == nil && parseResult != nil {
		if parseResult.InputTokens > 0 || parseResult.OutputTokens > 0 {
			result.InputTokens = parseResult.InputTokens
			result.OutputTokens = parseResult.OutputTokens
			result.Tokens = parseResult.InputTokens + parseResult.OutputTokens
		}
		if parseResult.CostUSD > 0 {
			result.CostUSD = parseResult.CostUSD
		}
		if parseResult.SessionID != "" {
			result.AgentSessionID = parseResult.SessionID
		}
	}

	return result, nil
}

// stringWriter adapts *strings.Builder to io.Writer without allocating.
type stringWriter struct {
	sb *strings.Builder
}

func (w *stringWriter) Write(p []byte) (int, error) {
	return w.sb.Write(p)
}

// claudeStreamArgsUnsupported reports whether the claude CLI rejected the
// stream-json flags. Used by the fallback path to retry with legacy args.
func claudeStreamArgsUnsupported(stderr string) bool {
	lower := strings.ToLower(stderr)
	return strings.Contains(lower, "unknown option") ||
		strings.Contains(lower, "unrecognized option") ||
		strings.Contains(lower, "invalid value for --output-format") ||
		strings.Contains(lower, "unknown argument") ||
		strings.Contains(lower, "unknown flag")
}

// runClaudeWithFallback attempts the streaming path first and, if the claude
// CLI rejects the stream-json flags, retries with the legacy buffered
// --print/-p/--output-format=json invocation so existing non-streaming
// contracts remain intact.
func runClaudeWithFallbackFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
	result, err := runClaudeStreamingFn(r, ctx, harness, harnessName, model, resolvedOpts, prompt, execDir, timeout)
	if err != nil {
		return nil, err
	}
	if result == nil {
		return nil, nil
	}
	// Streaming path succeeded (even if the bead itself failed).
	if result.ExitCode != 2 || !claudeStreamArgsUnsupported(result.Stderr) {
		return result, nil
	}

	// claude CLI rejected stream-json (older build). Retry with the legacy
	// non-streaming args so the run still completes.
	legacyHarness := harness
	legacyHarness.BaseArgs = []string{"--print", "-p", "--output-format", "json"}
	args := BuildArgs(legacyHarness, buildArgsInputFromRunArgs(resolvedOpts), model)
	stdin := ""
	if harness.PromptMode == "stdin" {
		stdin = prompt
	}
	start := time.Now()
	execResult, execErr := r.Executor.ExecuteInDir(ctx, harness.Binary, args, stdin, execDir)
	elapsed := time.Since(start)
	return r.processResult(harnessName, model, harness, execResult, execErr, elapsed, ctx), nil
}

// finalizeClaudeResult writes the session log entry and records the routing
// outcome, mirroring the tail end of Runner.Run for the non-streaming path.
func finalizeClaudeResult(r *Runner, result *Result, opts RunArgs, prompt string, elapsed time.Duration) {
	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
}

	return result, nil
}

// drainServiceEvents reads service events and returns the final-event payload,
// the accumulated tool-call log, the routing decision (when present in the
// routing_decision start event), and the power of the selected model (0 when
// the routing_decision event does not include candidate power components).
// A sustained run of no-op compaction telemetry is converted into a synthetic
// stalled final so execute-bead result details identify the time-based
// breaker instead of waiting for the outer wall clock.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, []ToolCallEntry, *serviceRoutingActual, int) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var toolCalls []ToolCallEntry
	pending := make(map[string]*ToolCallEntry) // call_id -> entry awaiting result
	var noopCompactions serviceNoopCompactionStreak
	var noopTimer *time.Timer
	var noopTimerC <-chan time.Time
	defer func() { stopNoopCompactionTimer(noopTimer) }()

	for {
		select {
		case <-noopTimerC:
			detail := noopCompactions.detail(serviceNoopCompactionWallClockLimit, serviceNoopCompactionWallClockLimit)
			return &serviceFinalData{
				Status: "stalled",
				Error:  detail,
			}, toolCallsWithPending(toolCalls, pending), routing, routingPower
		case ev, ok := <-events:
			if !ok {
				// Any tool_call without a matching tool_result still gets recorded.
				return final, toolCallsWithPending(toolCalls, pending), routing, routingPower
			}
			if isNoopCompactionEvent(ev) {
				detail, started := noopCompactions.record(eventTimestamp(ev), serviceNoopCompactionWallClockLimit)
				if started {
					noopTimer, noopTimerC = resetNoopCompactionTimer(noopTimer, serviceNoopCompactionWallClockLimit)
				}
				if detail != "" {
					return &serviceFinalData{
						Status: "stalled",
						Error:  detail,
					}, toolCallsWithPending(toolCalls, pending), routing, routingPower
				}
				continue
			}
			if isServiceProgressEvent(ev) {
				noopCompactions.reset()
				stopNoopCompactionTimer(noopTimer)
				noopTimerC = nil
			}

			switch string(ev.Type) {
			case serviceEventRoutingDecision:
				var payload struct {
					Harness    string `json:"harness"`
					Provider   string `json:"provider"`
					Model      string `json:"model"`
					Candidates []struct {
						Model              string  `json:"model"`
						Eligible           bool    `json:"eligible"`
						CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
						CostSource         string  `json:"cost_source"`
						Components         struct {
							Power    int     `json:"power"`
							SpeedTPS float64 `json:"speed_tps"`
						} `json:"components"`
					} `json:"candidates"`
				}
				if err := json.Unmarshal(ev.Data, &payload); err == nil {
					routing = &serviceRoutingActual{
						Harness:  payload.Harness,
						Provider: payload.Provider,
						Model:    payload.Model,
					}
					for _, c := range payload.Candidates {
						if c.Eligible && c.Model == payload.Model {
							routingPower = c.Components.Power
							routing.PredictedPower = c.Components.Power
							routing.PredictedSpeedTPS = c.Components.SpeedTPS
							routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
							routing.PredictedCostSource = c.CostSource
							break
						}
					}
				}
			case serviceEventToolCall:
				var data serviceToolCallData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					entry := &ToolCallEntry{
						Tool:  data.Name,
						Input: string(data.Input),
					}
					pending[data.ID] = entry
				}
			case serviceEventToolResult:
				var data serviceToolResultData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					if entry, ok := pending[data.ID]; ok {
						entry.Output = data.Output
						entry.Error = data.Error
						entry.Duration = int(data.DurationMS)
						toolCalls = append(toolCalls, *entry)
						delete(pending, data.ID)
					}
				}
			case serviceEventFinal:
				var data serviceFinalData
				if err := json.Unmarshal(ev.Data, &data); err == nil {
					final = &data
				}
			}
		}
	}
}

func resetNoopCompactionTimer(timer *time.Timer, limit time.Duration) (*time.Timer, <-chan time.Time) {
	if limit <= 0 {
		return timer, nil
	}
	if timer == nil {
		timer = time.NewTimer(limit)
		return timer, timer.C
	}
	stopNoopCompactionTimer(timer)
	timer.Reset(limit)
	return timer, timer.C
}

func stopNoopCompactionTimer(timer *time.Timer) {
	if timer == nil {
		return
	}
	if !timer.Stop() {
		select {
		case <-timer.C:
		default:
		}
	}
}

type serviceNoopCompactionStreak struct {
	start time.Time
	count int
}

func (s *serviceNoopCompactionStreak) record(ts time.Time, limit time.Duration) (string, bool) {
	if limit <= 0 {
		return "", false
	}
	if ts.IsZero() {
		ts = time.Now().UTC()
	}
	started := false
	if s.count == 0 {
		s.start = ts
		started = true
	}
	s.count++
	elapsed := ts.Sub(s.start)
	if elapsed < limit {
		return "", started
	}
	return s.detail(elapsed, limit), started
}

func (s *serviceNoopCompactionStreak) detail(elapsed, limit time.Duration) string {
	if elapsed < limit {
		elapsed = limit
	}
	return fmt.Sprintf("%s: time-based breaker fired after %s of consecutive no-op compaction events (limit %s, count %d)",
		serviceNoopCompactionWallClockReason,
		elapsed.Round(time.Second),
		limit.Round(time.Second),
		s.count)
}

func (s *serviceNoopCompactionStreak) reset() {
	s.start = time.Time{}
	s.count = 0
}

func eventTimestamp(ev agentlib.ServiceEvent) time.Time {
	if !ev.Time.IsZero() {
		return ev.Time
	}
	return time.Now().UTC()
}

func isNoopCompactionEvent(ev agentlib.ServiceEvent) bool {
	switch string(ev.Type) {
	case serviceEventCompaction, serviceEventCompactionEnd:
	default:
		return false
	}
	var payload struct {
		NoCompaction bool `json:"no_compaction"`
	}
	if err := json.Unmarshal(ev.Data, &payload); err != nil {
		return false
	}
	return payload.NoCompaction
}

func isServiceProgressEvent(ev agentlib.ServiceEvent) bool {
	switch string(ev.Type) {
	case serviceEventProgress, serviceEventTextDelta, serviceEventToolCall, serviceEventToolResult, serviceEventCompaction, serviceEventCompactionEnd:
		return true
	default:
		return false
	}
}

func toolCallsWithPending(toolCalls []ToolCallEntry, pending map[string]*ToolCallEntry) []ToolCallEntry {
	for _, entry := range pending {
		toolCalls = append(toolCalls, *entry)
	}
	return toolCalls
}

