		Type: "final",
		Time: time.Date(2026, 4, 30, 12, 0, 1, 0, time.UTC),
		Data: finalPayload,
	}
	close(events)

	_, _, routing, actualPower := drainServiceEvents(events)
	assert.Equal(t, 65, actualPower,
